To write comprehensive unit tests for the `flatten_dict` function using `pytest`, we'll cover various scenarios including happy paths, edge cases, and error conditions.

```python
import pytest
from typing import Dict, Any

# The function to be tested
def flatten_dict(d: Dict, parent_key: str = '', sep: str = '.') -> Dict:
    items = []
    for k, v in d.items():
        new_key = f'{parent_key}{sep}{k}' if parent_key else k
        if isinstance(v, dict):
            items.extend(flatten_dict(v, new_key, sep).items())
        else:
            items.append((new_key, v))
    return dict(items)

class TestFlattenDict:

    # --- Happy Path Tests ---

    def test_empty_dict(self):
        """Test with an empty input dictionary."""
        assert flatten_dict({}) == {}

    def test_already_flat_dict(self):
        """Test with a dictionary that is already flat."""
        d = {'a': 1, 'b': 'hello', 'c': True}
        assert flatten_dict(d) == {'a': 1, 'b': 'hello', 'c': True}

    def test_single_level_nesting(self):
        """Test with a dictionary having one level of nesting."""
        d = {'a': 1, 'b': {'c': 2, 'd': 'world'}}
        expected = {'a': 1, 'b.c': 2, 'b.d': 'world'}
        assert flatten_dict(d) == expected

    def test_deeply_nested_dict(self):
        """Test with a dictionary having multiple levels of nesting."""
        d = {'a': {'b': {'c': 1, 'd': {'e': 2, 'f': 'deep'}}}}
        expected = {'a.b.c': 1, 'a.b.d.e': 2, 'a.b.d.f': 'deep'}
        assert flatten_dict(d) == expected

    def test_mixed_types_and_none_values(self):
        """Test with various data types including None, lists, and booleans."""
        d = {
            'id': 123,
            'user': {
                'name': 'Alice',
                'email': None,
                'tags': ['admin', 'active']
            },
            'active': True
        }
        expected = {
            'id': 123,
            'user.name': 'Alice',
            'user.email': None,
            'user.tags': ['admin', 'active'], # Lists are treated as values, not flattened
            'active': True
        }
        assert flatten_dict(d) == expected

    def test_multiple_top_level_nested_keys(self):
        """Test a complex dictionary with multiple nested branches."""
        d = {
            'user': {'name': 'Bob', 'age': 30},
            'address': {'street': '123 Main', 'city': 'Anytown'},
            'contact': {'email': 'bob@example.com'}
        }
        expected = {
            'user.name': 'Bob',
            'user.age': 30,
            'address.street': '123 Main',
            'address.city': 'Anytown',
            'contact.email': 'bob@example.com'
        }
        assert flatten_dict(d) == expected

    # --- Edge Cases ---

    def test_dict_with_empty_nested_dict(self):
        """Test a dictionary containing an empty nested dictionary."""
        d = {'a': 1, 'b': {}, 'c': {'d': 2}}
        expected = {'a': 1, 'c.d': 2} # Empty dict 'b' should not produce any items
        assert flatten_dict(d) == expected

    def test_custom_separator(self):
        """Test with a custom separator character."""
        d = {'a': {'b': {'c': 1}}}
        expected = {'a_b_c': 1}
        assert flatten_dict(d, sep='_') == expected

        d2 = {'x': {'y': 'val'}, 'z': 10}
        expected2 = {'x::y': 'val', 'z': 10}
        assert flatten_dict(d2, sep='::') == expected2

    def test_keys_containing_separator(self):
        """Test when dictionary keys themselves contain the separator character."""
        d = {'a.b': 1, 'c': {'d.e': 2}}
        expected = {'a.b': 1, 'c.d.e': 2} # The separator is just added, no special handling for existing dots in keys
        assert flatten_dict(d) == expected

        d2 = {'key_with_sep': {'nested_key_with_sep': 'value'}, 'another_key': 1}
        expected2 = {'key_with_sep_nested_key_with_sep': 'value', 'another_key': 1}
        assert flatten_dict(d2, sep='_') == expected2

    def test_numeric_keys(self):
        """Test with numeric keys (which are valid in Python dictionaries)."""
        d = {1: 'one', 2: {3: 'three'}}
        expected = {1: 'one', '2.3': 'three'}
        assert flatten_dict(d) == expected

    # --- Error Cases ---

    @pytest.mark.parametrize("invalid_input", [
        None,
        123,
        "not_a_dict",
        [1, 2, 3],
        (1, 2),
        set([1, 2])
    ])
    def test_non_dict_input_raises_attribute_error(self, invalid_input):
        """
        Test that passing non-dictionary types as input raises an AttributeError
        because `d.items()` will be called on a non-dict object.
        """
        with pytest.raises(AttributeError):
            flatten_dict(invalid_input)

    # Note: The function signature `d: dict` implies the input should be a dict.
    # Python's type hints are for static analysis, not runtime enforcement.
    # The actual runtime error for non-dict inputs is typically AttributeError
    # when trying to call `.items()`.
